This is the only function with real, non-UI logic: builds the command, sets `Setpgid`, wires a custom `cmd.Cancel` that kills the whole process group, merges stderr into stdout, and streams lines via `onLine`. None of this is exercised.

Untested behavior:
- Correct argv is built (`uv run main.py <name> --limit <limit>`) and `cmd.Dir` is set to `crawlerDir`.
- `onLine` is called once per stdout line, in order, and stderr lines are interleaved (merged stream).
- Non-zero exit / process error is returned from `cmd.Wait()`.
- Context cancellation triggers `cmd.Cancel` and kills the process group (not just the direct child) — this is the subtlest piece of logic in the file and has no coverage at all.
- `StdoutPipe()` error path (`return err`) — currently unreachable in practice but untested.
- `cmd.Start()` failure path (e.g., `uv` not on `PATH`).

Since this shells out to a real binary, it needs a fake-executable trick rather than mocking `exec.Cmd` directly:

```go
// runcrawler_test.go
package main

import (
	"context"
	"os"
	"os/exec"
	"testing"
	"time"
)

// fakeUV builds a tiny helper binary (or reuses TestHelperProcess pattern)
// that stands in for `uv` on PATH, so runCrawler exercises real process
// semantics without depending on the actual crawler.
func TestRunCrawler_StreamsStdoutLines(t *testing.T) {
	dir := t.TempDir()
	writeFakeUV(t, dir, `#!/bin/sh
echo "line one"
echo "line two"
exit 0
`)
	t.Setenv("PATH", dir+":"+os.Getenv("PATH"))

	var got []string
	err := runCrawler(context.Background(), "some-provider", 5, ".", func(line string) {
		got = append(got, line)
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	want := []string{"line one", "line two"}
	if !equal(got, want) {
		t.Errorf("got %v, want %v", got, want)
	}
}

func TestRunCrawler_MergesStderrIntoStdout(t *testing.T) {
	dir := t.TempDir()
	writeFakeUV(t, dir, `#!/bin/sh
echo "out line"
echo "err line" >&2
exit 0
`)
	t.Setenv("PATH", dir+":"+os.Getenv("PATH"))

	var got []string
	_ = runCrawler(context.Background(), "p", 1, ".", func(line string) { got = append(got, line) })
	// both lines should appear somewhere in got (order across streams is not guaranteed)
}

func TestRunCrawler_NonZeroExitReturnsError(t *testing.T) {
	dir := t.TempDir()
	writeFakeUV(t, dir, "#!/bin/sh\nexit 1\n")
	t.Setenv("PATH", dir+":"+os.Getenv("PATH"))

	if err := runCrawler(context.Background(), "p", 1, ".", func(string) {}); err == nil {
		t.Fatal("expected error for non-zero exit, got nil")
	}
}

func TestRunCrawler_ContextCancelKillsProcessGroup(t *testing.T) {
	dir := t.TempDir()
	// spawns a background child (simulating python) and sleeps; on SIGKILL of
	// the group, both the shell and its child should die.
	writeFakeUV(t, dir, `#!/bin/sh
sleep 30 &
sleep 30
`)
	t.Setenv("PATH", dir+":"+os.Getenv("PATH"))

	ctx, cancel := context.WithCancel(context.Background())
	done := make(chan error, 1)
	go func() {
		done <- runCrawler(ctx, "p", 1, ".", func(string) {})
	}()
	time.Sleep(200 * time.Millisecond)
	cancel()

	select {
	case <-done:
	case <-time.After(5 * time.Second):
		t.Fatal("runCrawler did not return after cancel; process group likely not killed")
	}
}

func TestRunCrawler_StartFailure_BinaryNotFound(t *testing.T) {
	t.Setenv("PATH", "/nonexistent")
	err := runCrawler(context.Background(), "p", 1, ".", func(string) {})
	if err == nil {
		t.Fatal("expected error when uv is not on PATH")
	}
}

func writeFakeUV(t *testing.T, dir, script string) {
	t.Helper()
	path := dir + "/uv"
	if err := os.WriteFile(path, []byte(script), 0o755); err != nil {
		t.Fatal(err)
	}
}

func equal(a, b []string) bool { /* helper */ return len(a) == len(b) }
var _ = exec.Command // placeholder import usage
```

It calls `runCrawler` directly (no seam for injection), spawns one goroutine per provider, and prints to stdout. Gaps:
- All `names` are launched concurrently and `wg.Wait()` blocks until every one finishes — untested.
- Per-provider error is printed but doesn't abort the others — untested.
- SIGTERM/`os.Interrupt` cancellation fans out to all running crawlers — untested (also currently only reachable via a real signal, no injection point).

**Gap in testability, not just coverage:** `runCrawler` is called by name, not as an injectable field, so `runHeadless` can't be unit-tested in isolation without also spinning up fake `uv` processes for every provider. Consider extracting a `type crawlerFunc func(ctx, name, limit, dir string, onLine func(string)) error` field/parameter so `runHeadless` can be tested with a stub:

```go
func TestRunHeadless_AggregatesAllProviders(t *testing.T) {
	var mu sync.Mutex
	seen := map[string]bool{}
	stub := func(ctx context.Context, name string, limit int, dir string, onLine func(string)) error {
		mu.Lock()
		seen[name] = true
		mu.Unlock()
		onLine("ok")
		return nil
	}
	runHeadlessWith(stub, []string{"a", "b", "c"}, 1, ".") // proposed injectable variant
	if len(seen) != 3 {
		t.Fatalf("expected 3 providers run, got %d", len(seen))
	}
}

func TestRunHeadless_OneProviderErrorsDoesNotAbortOthers(t *testing.T) {
	stub := func(ctx context.Context, name string, limit int, dir string, onLine func(string)) error {
		if name == "b" {
			return errors.New("boom")
		}
		return nil
	}
	// assert all three still ran despite b's error, by checking a completion counter
}
```

`-limit`, `-providers`, `-crawler-dir`, `-headless` are parsed inline in `main`, so the "comma-separated providers" splitting logic (`strings.Split(*providersFlag, ",")`) is untested in isolation. Minor gap — consider extracting `parseProviderNames(flagValue string, all []string) []string` as a pure function:

```go
func TestParseProviderNames(t *testing.T) {
	cases := []struct{ in string; want []string }{
		{"all", providers},
		{"newsmada", []string{"newsmada"}},
		{"newsmada,2424-mg", []string{"newsmada", "2424-mg"}},
		{"", []string{""}}, // documents current behavior: empty string yields one empty name — likely a bug worth flagging
	}
	for _, c := range cases {
		got := parseProviderNames(c.in, providers)
		// compare got == c.want
	}
}
```
Note the `""` case: today, `-providers=""` would `strings.Split("", ",")` → `[""]`, and `runHeadless` would launch a crawler for the empty provider name. That's an untested edge case worth deciding on (validate and error, vs. silently no-op).

