```go
// tui_test.go
package main

import (
	"testing"

	tea "github.com/charmbracelet/bubbletea"
)

func key(s string) tea.KeyMsg {
	return tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune(s)}
	// for named keys (up/down/enter/esc/ctrl+c) construct via tea.Key{Type: tea.KeyEnter} etc.
}

func TestHandleKey_Picking_CursorBounds(t *testing.T) {
	m := newModel(10, ".")
	// cursor should not go below 0
	m.handleKey(tea.KeyMsg{Type: tea.KeyUp})
	if m.cursor != 0 {
		t.Errorf("cursor = %d, want 0", m.cursor)
	}
	// cursor should not exceed len(providers)-1
	for i := 0; i < len(providers)+5; i++ {
		m.handleKey(tea.KeyMsg{Type: tea.KeyDown})
	}
	if m.cursor != len(providers)-1 {
		t.Errorf("cursor = %d, want %d", m.cursor, len(providers)-1)
	}
}

func TestHandleKey_Picking_ToggleAndSelectAll(t *testing.T) {
	m := newModel(10, ".")
	m.handleKey(tea.KeyMsg{Type: tea.KeySpace})
	if !m.selected[0] {
		t.Error("expected provider 0 selected after space")
	}
	m.handleKey(tea.KeyMsg{Type: tea.KeySpace}) // toggle off
	if m.selected[0] {
		t.Error("expected provider 0 deselected")
	}
	m.handleKey(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune("a")})
	if m.countSelected() != len(providers) {
		t.Errorf("expected all selected, got %d", m.countSelected())
	}
}

func TestHandleKey_Picking_EnterWithNoneSelectedSelectsAll(t *testing.T) {
	m := newModel(10, ".")
	m.handleKey(tea.KeyMsg{Type: tea.KeyEnter})
	if m.countSelected() != len(providers) {
		t.Error("enter with nothing selected should select all")
	}
	if m.screen != screenLimit {
		t.Error("enter should transition to screenLimit")
	}
}

func TestHandleKey_Limit_RejectsInvalidAndNegative(t *testing.T) {
	m := newModel(10, ".")
	m.screen = screenLimit
	m.limitInput.SetValue("-1")
	m.handleKey(tea.KeyMsg{Type: tea.KeyEnter})
	if m.screen != screenLimit {
		t.Error("negative limit should not advance screen")
	}

	m.limitInput.SetValue("not-a-number")
	m.handleKey(tea.KeyMsg{Type: tea.KeyEnter})
	if m.screen != screenLimit {
		t.Error("non-numeric limit should not advance screen")
	}
}

func TestHandleKey_Limit_ZeroIsValid(t *testing.T) {
	m := newModel(10, ".")
	m.screen = screenLimit
	m.limitInput.SetValue("0")
	m.handleKey(tea.KeyMsg{Type: tea.KeyEnter})
	if m.limit != 0 {
		t.Errorf("limit = %d, want 0", m.limit)
	}
	// NOTE: this calls startRun(), which spawns goroutines that call
	// m.program.Send() — program is nil here, so this WILL PANIC.
	// See "gap: startRun requires m.program" below before writing this test.
}

func TestHandleKey_Limit_EscReturnsToPicking(t *testing.T) {
	m := newModel(10, ".")
	m.screen = screenLimit
	m.handleKey(tea.KeyMsg{Type: tea.KeyEsc})
	if m.screen != screenPicking {
		t.Error("esc should return to picking screen")
	}
}

func TestHandleKey_Running_CursorBounds(t *testing.T) {
	m := newModel(10, ".")
	m.runOrder = []string{"a", "b", "c"}
	m.screen = screenRunning
	m.statuses = map[string]*providerStatus{"a": {}, "b": {}, "c": {}}
	m.vp.Width, m.vp.Height = 40, 10

	m.handleKey(tea.KeyMsg{Type: tea.KeyUp}) // already at 0, should stay
	if m.runCursor != 0 {
		t.Errorf("runCursor = %d, want 0", m.runCursor)
	}
	m.handleKey(tea.KeyMsg{Type: tea.KeyDown})
	m.handleKey(tea.KeyMsg{Type: tea.KeyDown})
	m.handleKey(tea.KeyMsg{Type: tea.KeyDown}) // past end
	if m.runCursor != 2 {
		t.Errorf("runCursor = %d, want 2", m.runCursor)
	}
}

func TestHandleKey_QuitCallsCancel(t *testing.T) {
	m := newModel(10, ".")
	called := false
	m.cancel = func() { called = true }
	_, cmd := m.handleKey(tea.KeyMsg{Type: tea.KeyCtrlC})
	if !called {
		t.Error("ctrl+c should call m.cancel")
	}
	if cmd == nil {
		t.Error("expected tea.Quit command")
	}
}

func TestHandleKey_QuitWithNilCancelDoesNotPanic(t *testing.T) {
	m := newModel(10, ".") // m.cancel is nil (no run started yet)
	defer func() {
		if r := recover(); r != nil {
			t.Fatalf("q with nil cancel panicked: %v", r)
		}
	}()
	m.handleKey(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune("q")})
}
