	m := newModel(10, ".")
	m.statuses["p"] = &providerStatus{state: stateRunning}
	m.pending = 1
	m.Update(doneMsg{provider: "p", err: nil})
	if m.pending != 0 {
		t.Errorf("pending = %d, want 0", m.pending)
	}
	if m.statuses["p"].state != stateDone {
		t.Errorf("state = %v, want stateDone", m.statuses["p"].state)
	}
}

func TestUpdate_DoneMsg_WithError_SetsErrorStateAndAppendsLine(t *testing.T) {
	m := newModel(10, ".")
	m.statuses["p"] = &providerStatus{}
	m.Update(doneMsg{provider: "p", err: errors.New("boom")})
	st := m.statuses["p"]
	if st.state != stateError {
		t.Errorf("state = %v, want stateError", st.state)
	}
	if len(st.lines) != 1 || st.lines[0] != "error: boom" {
		t.Errorf("lines = %v", st.lines)
	}
}

func TestUpdate_WindowSizeMsg_UpdatesLayoutAndViewport(t *testing.T) {
	m := newModel(10, ".")
	m.Update(tea.WindowSizeMsg{Width: 80, Height: 24})
	if m.width != 80 || m.height != 24 {
		t.Error("width/height not updated")
	}
}
