```go
func TestLayout(t *testing.T) {
	cases := []struct {
		name          string
		w, h          int
		wantW, wantH  int
	}{
		{"normal", 100, 40, 100 - sidenavWidth - 4, 40 - 6},
		{"tiny width clamps to 10", 20, 40, 10, 34},
		{"tiny height clamps to 3", 100, 5, 68, 3},
		{"zero size", 0, 0, 10, 3},
		{"negative size (window not yet sized)", -1, -1, 10, 3},
	}
	for _, c := range cases {
		t.Run(c.name, func(t *testing.T) {
			m := &model{width: c.w, height: c.h}
			gotW, gotH := m.layout()
			if gotW != c.wantW || gotH != c.wantH {
				t.Errorf("layout() = (%d,%d), want (%d,%d)", gotW, gotH, c.wantW, c.wantH)
			}
		})
	}
}

func TestHighlighted(t *testing.T) {
	m := &model{runOrder: []string{"a", "b"}, runCursor: 1}
	if got := m.highlighted(); got != "b" {
		t.Errorf("highlighted() = %q, want b", got)
	}
	m.runCursor = -1
	if got := m.highlighted(); got != "" {
		t.Errorf("negative cursor: highlighted() = %q, want empty", got)
	}
	m.runCursor = 99
	if got := m.highlighted(); got != "" {
		t.Errorf("out-of-range cursor: highlighted() = %q, want empty", got)
	}
	m.runOrder = nil
	m.runCursor = 0
	if got := m.highlighted(); got != "" {
		t.Errorf("empty runOrder: highlighted() = %q, want empty", got)
	}
}

