	m := &model{selected: map[int]bool{0: true, 1: false, 2: true}}
	if got := m.countSelected(); got != 2 {
		t.Errorf("countSelected() = %d, want 2", got)
	}
	m2 := &model{selected: map[int]bool{}}
	if got := m2.countSelected(); got != 0 {
		t.Errorf("empty map: countSelected() = %d, want 0", got)
	}
