func TestTruncate(t *testing.T) {
	cases := []struct {
		name string
		s    string
		n    int
		want string
	}{
		{"shorter than n", "abc", 10, "abc"},
		{"equal to n", "abcde", 5, "abcde"},
		{"longer than n", "abcdefgh", 5, "abcd…"},
		{"n=1", "abcdefgh", 1, "a"},
		{"n=0", "abcdefgh", 0, ""},
		{"empty string", "", 5, ""},
		// documents a real gap: len() counts bytes, not runes, so multi-byte
		// UTF-8 input (e.g. provider names with accents) can be sliced mid-rune,
		// producing invalid UTF-8 / a corrupted glyph instead of a clean "…".
		{"multi-byte unicode truncation", "café-longnametoforce", 5, "caf" /* + corrupted byte, not "café…" */},
	}
	for _, c := range cases {
		t.Run(c.name, func(t *testing.T) {
			if got := truncate(c.s, c.n); got != c.want {
				t.Errorf("truncate(%q, %d) = %q, want %q", c.s, c.n, got, c.want)
			}
		})
	}
}

